--
-- Table structure for table `crop`
--

DROP TABLE IF EXISTS `crop`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `crop` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT 'id',
  `cropName` varchar(256) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '作物名称',
  `cropType` varchar(256) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '作物类型',
  `imageId` varchar(1024) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '图片id',
  `growthStage` varchar(1024) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '生长阶段（json 数组）',
  `productionRecords` varchar(1024) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '生产记录（json 数组）',
  `transportationRecords` varchar(1024) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '运输记录（json 数组）',
  `qualityInspection` varchar(1024) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '质量检测（json 数组）',
  `plantTime` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '种植时间',
  `harvestTime` datetime DEFAULT NULL COMMENT '收获时间',
  `store` tinyint DEFAULT NULL COMMENT '是否入库',
  `userId` bigint DEFAULT NULL COMMENT '创建用户 id',
  `supplierId` bigint DEFAULT NULL COMMENT '供应商 id',
  `farmId` bigint DEFAULT NULL COMMENT '农场 id',
  `manufacturerId` bigint DEFAULT NULL COMMENT '生产商 id',
  `processingFactoryId` bigint DEFAULT NULL COMMENT '加工厂 id',
  `createTime` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updateTime` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `isDelete` tinyint DEFAULT '0' COMMENT '是否删除',
  PRIMARY KEY (`id`),
  KEY `idx_userId` (`userId`)
) ENGINE=InnoDB AUTO_INCREMENT=2039573115766018050 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='作物';
/*!40101 SET character_set_client = @saved_cs_client */;

