/*!40000 ALTER TABLE `crop` DISABLE KEYS */;
INSERT INTO `crop` VALUES (1894274578539249666,'小麦','粮食作物','1911483857104949250','{\"Preparation-stage\":\"\",\"Sowing-stage\":\"\",\"Growth-stage\":\"\",\"\":\"出苗\\n田间管理：包括除草、间苗、施肥、浇水等工作，确保苗期生长健康。\\n生长发育：植物在这一阶段主要进行营养积累，发育根、茎、叶等部分。\\n施肥与灌溉：根据作物的生长需求，适时施肥，保持充足的水分供应。\"}','{\"Pollination-stage\":\"\",\"developmental-stage\":\"\",\"Harvesting-Stage\":\"\",\"\":\"成熟期：作物的果实或种子完全成熟，达到最佳收获时间。\\n收获：使用人工或机械设备进行收割。\"}','{\"Harvest-Processing\":\"\",\"Storage-records\":\"\",\"\":\"储存：将收获的作物进行储存或加工，以延长保存期，防止腐烂。\"}','{\"pesticide-residue\":\"\",\"food-safety\":\"\",\"\":\"食品安全标准：确保作物符合国家或地区的食品安全标准，例如农作物的农残、重金属、微生物等指标符合食品安全的要求。\\n标签与溯源：检测作物的标签和溯源系统是否准确，确保消费者能够追溯到生产源头。\"}','2026-02-25 14:33:48','2026-04-02 15:01:45',1,1876557233851129858,0,0,0,0,'2026-02-25 14:33:48','2026-04-02 15:01:44',0),(1894274614861922305,'大米','粮食作物','1911483891997364226','{\"Preparation-stage\":\"\",\"Sowing-stage\":\"\",\"Growth-stage\":\"\",\"\":\"出苗：种子发芽，幼苗长出。\\n田间管理：包括除草、间苗、施肥、浇水等工作，确保苗期生长健康。\\n生长发育：植物在这一阶段主要进行营养积累，发育根、茎、叶等部分。\\n施肥与灌溉：根据作物的生长需求，适时施肥，保持充足的水分供应。\"}','{\"Pollination-stage\":\"\",\"developmental-stage\":\"\",\"Harvesting-Stage\":\"\",\"\":\"成熟期：作物的果实或种子完全成熟，达到最佳收获时间。\\n收获：使用人工或机械设备进行收割。\"}','{\"Harvest-Processing\":\"\",\"Storage-records\":\"\",\"\":\"储存：将收获的作物进行储存或加工，以延长保存期，防止腐烂。\"}','{\"pesticide-residue\":\"\",\"food-safety\":\"\",\"\":\"食品安全标准：确保作物符合国家或地区的食品安全标准，例如农作物的农残、重金属、微生物等指标符合食品安全的要求。\\n标签与溯源：检测作物的标签和溯源系统是否准确，确保消费者能够追溯到生产源头。\"}','2026-02-25 14:33:56','2026-03-31 23:48:55',2,1876557233851129858,0,0,0,0,'2026-02-25 14:33:56','2026-04-02 12:58:12',1),(1894274635967660034,'玉米','粮食作物','1911484123032211458','{\"Preparation-stage\":\"\",\"Sowing-stage\":\"\",\"Growth-stage\":\"\",\"\":\"出苗：种子发芽，幼苗长出。\\n田间管理：包括除草、间苗、施肥、浇水等工作，确保苗期生长健康。\\n生长发育：植物在这一阶段主要进行营养积累，发育根、茎、叶等部分。\\n施肥与灌溉：根据作物的生长需求，适时施肥，保持充足的水分供应。\"}','{\"Pollination-stage\":\"\",\"developmental-stage\":\"\",\"Harvesting-Stage\":\"\",\"\":\"成熟期：作物的果实或种子完全成熟，达到最佳收获时间。\\n收获：使用人工或机械设备进行收割。\"}','{\"Harvest-Processing\":\"\",\"Storage-r