INSERT INTO `activity` VALUES (13,'【有奖征集】新一期评测活动来啦','《无畏契约》（VALORANT）是由拳头游戏研发，中国大陆地区由腾讯游戏代理发行的一款以英雄为核心的5V5第一人称战术射击PC游戏。游戏注重技巧和创造性玩法，拥有极强的竞技性与策略性，战斗节奏激烈，爽快感强，还有丰富多样的玩法模式。','<p>长假在即，终于可以有更多时间喊上小伙伴一起大瓦特瓦了！同时本期夜市已开启，大家有没有开出自己想要的神中神呢～<br/>诚邀各位瓦友在【WeGame无畏契约专区-用户评测区】留下您的评测&amp;感受，对于有价值的评论我们会随机抽取5名瓦友， 每人给到 【3000无畏点券】~<br/>活动时间：即日起~10.8日 24:00<br/>参与方式： 在WeGame上关注《无畏契约》， 并在用户评测区留下您的评测，同时附上您的游戏ID（昵称+#后面的数字）， 对于中奖的玩家我们会直接回复您，并于5个工作日内将奖励直接发至您的游戏账户。<br/>规则说明：<br/>1、每人限参与一次，请勿重复留言，请勿抄袭他人留言。 评测内容请符合WeGame社区规范， 且游戏评测尽可能全面。<br/>2、评测日期应在活动时间内。<br/>3、【WeGame无畏契约专区-用户评测区】进入方式：游戏详情 - WeGame游戏商店或通过下述方式进入</p><p><img src=\"http://localhost:9090/files/1740978441338-image.png\"/></p>','2025-03-04','2025-05-31','线上','版本活动','拳头游戏',2,'http://localhost:9090/files/1740978553403-88a5f8defc5f88f4ac90b2c0f912b04.png');
/*!40000 ALTER TABLE `activity` ENABLE KEYS */;
UNLOCK TABLES;

