DROP TABLE IF EXISTS `farm_info`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `farm_info` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT 'id',
  `userId` bigint NOT NULL COMMENT '用户 id',
  `name` varchar(256) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '农场昵称',
  `avatar` varchar(1024) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '农场头像',
  `profile` varchar(512) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '农场简介',
  `phone` varchar(512) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '农场电话',
  `email` varchar(512) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '农场邮箱',
