DROP TABLE IF EXISTS `invitation_info`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `invitation_info` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT 'id',
  `PartyAId` bigint NOT NULL COMMENT '甲方 id',
  `PartyAName` varchar(512) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '甲方名称',
  `PartyAType` varchar(64) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '甲方类型',
  `PartyAQualification` varchar(1024) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '甲方资质',
  `PartyBId` bigint DEFAULT NULL COMMENT '乙方 id',
  `PartyBName` varchar(512) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '乙方名称',
  `PartyBType` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '乙方类型',
  `PartyBQualification` varchar(1024) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '乙方资质',
