DROP TABLE IF EXISTS `orders`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `orders` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT 'id',
  `userId` bigint NOT NULL COMMENT '创建用户 id',
  `supplierId` bigint NOT NULL COMMENT '供应商 id',
  `detail` varchar(1024) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '详情（json 数组）',
  `bankAccountId` bigint DEFAULT NULL COMMENT '银行卡 id',
  `totalAmount` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '总金额',
  `note` varchar(256) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '订单备注',
  `userStatus` int NOT NULL DEFAULT '0' COMMENT '用户状态 0 -- 未支付， 1 -- 已下单， 2 -- 已收货， 3 -- 已完成， 4 -- 仅退款， 5 -- 退款退货, 6 -- 换货',
  `supplierStatus` int NOT NULL DEFAULT '0' COMMENT '供应商状态 0 -- 确认订单， 1 -- 待发货， 2 -- 已发货， 3 -- 待收货， 4 -- 待退款， 5 -- 待退款退货， 6 -- 待换货， 7 -- 已完成',
  `priority` int NOT NULL DEFAULT '0' COMMENT '优先级 0 -- 可选（默认）， 1 -- 低级， 2 -- 中级， 3 -- 高级， 4 -- 紧急',
  `createTime` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updateTime` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `isDelete` tinyint NOT NULL DEFAULT '0' COMMENT '是否删除',
  PRIMARY KEY (`id`),
  KEY `idx_userId` (`userId`)
) ENGINE=InnoDB AUTO_INCREMENT=2033159521504964610 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='订单';
