DROP TABLE IF EXISTS `processingfactory_info`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `processingfactory_info` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT 'id',
  `userId` bigint NOT NULL COMMENT '用户 id',
  `name` varchar(256) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '加工厂昵称',
  `avatar` varchar(1024) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '加工厂头像',
  `profile` varchar(512) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '加工厂简介',
  `phone` varchar(512) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '加工厂电话',
  `email` varchar(512) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '加工厂邮箱',
  `address` varchar(512) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '加工厂地址',
  `qualification` varchar(1024) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '加工厂资质（json 数组）',
  `role` varchar(256) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'user' COMMENT '加工厂角色：user/admin/ban',
  `status` int NOT NULL DEFAULT '0' COMMENT '加工厂状态 0 -- 活跃， 1 -- 不活跃',
  `createTime` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updateTime` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `isDelete` tinyint NOT NULL DEFAULT '0' COMMENT '是否删除',
  PRIMARY KEY (`id`),
  KEY `idx_userId` (`userId`)
) ENGINE=InnoDB AUTO_INCREMENT=1876604723191242755 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='加工厂信息';
