CREATE TABLE `supplier_info` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT 'id',
  `userId` bigint NOT NULL COMMENT '用户 id',
  `farmId` varchar(512) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '农场id',
  `farm` varchar(512) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '农场',
  `manufacturerId` varchar(512) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '生产商id',
  `manufacturer` varchar(512) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '生产商',
  `processingFactoryId` varchar(512) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '加工厂id',
  `processingFactory` varchar(512) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '加工厂',
  `name` varchar(256) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '供应商昵称',
  `avatar` varchar(1024) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '供应商头像',
  `profile` varchar(512) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '供应商简介',
