INSERT INTO `hitokoto` VALUES (1,'不管什么时候，能够改变世界的人都是一心追逐梦想的人。','口袋妖怪','小优','2025-03-03 16:22:11'),(2,'云峦波涛，千里枯路，江山故人我，晚秋行舟。','明日方舟','令','2025-03-03 16:22:40'),(3,'戏会落幕，人生却不会。','原神','云堇','2025-03-03 16:24:02'),(4,'狂风吹打山岩，自己却先粉身碎骨。','明日方舟','翎羽','2025-03-03 16:25:45'),(5,'只要你还记得我，我就会一直在你的身边。','符文工房',NULL,'2025-03-03 16:26:30'),(7,'那随风飘荡的蒲公英种子，会在什么时候决定自己的命运呢？','沙耶之歌','沙耶','2025-03-03 18:42:11'),(8,'夜醒众人漫漫夜，宝船乘风破浪声。','樱之诗',NULL,'2025-03-03 18:42:59'),(9,'成功不是终点，失败也不是终结，只有勇气才是永恒。','使命召唤：幽灵','西蒙·莱利','2025-03-03 19:03:09'),(10,'游戏人生','游戏人生','游戏人生','2025-03-03 19:34:27');
/*!40000 ALTER TABLE `hitokoto` ENABLE KEYS */;
UNLOCK TABLES;

