INSERT INTO `peripherals` VALUES (564,'李白凤求凰','王者荣耀 官方正版 凤求凰王者荣耀 官方正版 凤求凰','<p>图文详情</p><p><img src=\"https://img.alicdn.com/imgextra/i3/2875514337/O1CN01CqdQ7L1huOTNZQDN4_!!2875514337.jpg\"/></p><p><img src=\"https://img.alicdn.com/imgextra/i4/2875514337/O1CN01G3rxwF1huOTREE7qo_!!2875514337.jpg\"/></p><p><img src=\"https://img.alicdn.com/imgextra/i2/2875514337/O1CN01Zdvbpr1huOTA1ugv2_!!2875514337.jpg\"/></p><p><img src=\"https://img.alicdn.com/imgextra/i3/2875514337/O1CN01UwOmim1huOTQ7r3iv_!!2875514337.jpg\"/></p><p><img src=\"https://img.alicdn.com/imgextra/i4/2875514337/O1CN01E1aTg61huOTMb0Rdy_!!2875514337.jpg\"/></p><p><img src=\"https://img.alicdn.com/imgextra/i3/2875514337/O1CN0112bUDc1huOTH3vhfL_!!2875514337.jpg\"/></p><p><img src=\"https://img.alicdn.com/imgextra/i4/2875514337/O1CN01yaDiVH1huOTRzAH1g_!!2875514337.jpg\"/></p><p><img src=\"https://img.alicdn.com/imgextra/i2/2875514337/O1CN01YgPFN91huOTPPrr6W_!!2875514337.jpg\"/></p><p><img src=\"https://img.alicdn.com/imgextra/i2/2875514337/O1CN01kNdPt41huOTMazN7W_!!2875514337.jpg\"/></p><p><img src=\"https://img.alicdn.com/imgextra/i2/2875514337/O1CN01jhrSAm1huOTPPsnKG_!!2875514337.jpg\"/></p><p><img src=\"https://img.alicdn.com/imgextra/i1/2875514337/O1CN01MEXZ3T1huOTREBe1Z_!!2875514337.jpg\"/></p><p><img src=\"https://img.alicdn.com/imgextra/i3/O1CN01MsWlBa29wVnysxUvn_!!6000000008132-2-tps-750-880.png\"/></p>',3699,2,'http://localhost:9090/files/1742316094438-李白凤求凰.png','周边','2025-02-18 13:22:27',NULL,'active'),(565,'原神凝光','凝光，米哈游出品的游戏《原神》及其衍生作品中的角色，坐拥空中宫殿，有着大量传言的璃月权贵，脸上总是挂着优雅神秘的笑容。作为“璃月七星”中的天权星，她不仅象征着权力与律法，也代表着财富与才智 。其名下财富之多，全大陆鲜有人能望其项背','<p><img src=\"https://img.alicdn.com/imgextra/i1/2209046915691/O1CN01ZrmPFA1ruX0G0GIgu_!!2209046915691.jpg\"/></p><p><img src=\"https://img.alicdn.com/imgextra/i4/2209046915691/O1CN01gdKy3C1ruX0GbP9Qw_!!2209046915691.jpg\"/></p><p><img src=\"https://img.alicdn.com/imgextra/i1/2209046915691/O1CN01jgBZuw1ruX0IaVx5T_!!2209046915691.jpg\"/></p><p><img src=\"https://img.alicdn.