INSERT INTO `question` VALUES (1762726582099320833,'A + B','题目内容','[\"栈\",\"简单\"]','暴力破解',0,0,'[{\"input\":\"1 2\",\"output\":\"3 4\"}]','{\"timeLimit\":1000,\"memoryLimit\":1000,\"stackLimit\":1000}',0,0,1759173052197416962,'2024-02-28 14:29:01','2024-03-28 05:43:36',1),(1762726585161162754,'A + B','题目内容','[\"栈\",\"简单\"]','暴力破解',0,0,'[{\"input\":\"1 2\",\"output\":\"3 4\"}]','{\"timeLimit\":800,\"memoryLimit\":800,\"stackLimit\":800}',0,0,1759173052197416962,'2024-02-28 14:29:02','2024-03-22 01:12:36',1),(1762726588885704705,'A + B','题目内容','[\"栈\",\"简单\",\"二叉树\"]','暴力破解',0,0,'[{\"input\":\"2 3\",\"output\":\"4 5\"}]','{\"timeLimit\":1000,\"memoryLimit\":2000,\"stackLimit\":2000}',0,0,1759173052197416962,'2024-02-28 14:29:03','2024-03-28 05:43:42',1),(1762726591100297218,'A + B','题目内容','[\"栈\",\"简单\"]','暴力破解',0,0,'[{\"input\":\"1 2\",\"output\":\"3 4\"}]','{\"timeLimit\":1000,\"memoryLimit\":1000,\"stackLimit\":1000}',0,0,1759173052197416962,'2024-02-28 14:29:03','2024-03-22 01:12:36',1),(1762726592719298562,'A + B','题目内容','[\"栈\",\"简单\"]','暴力破解',0,0,'[{\"input\":\"1 2\",\"output\":\"3 4\"}]','{\"timeLimit\":1000,\"memoryLimit\":1000,\"stackLimit\":1000}',0,0,1759173052197416962,'2024-02-28 14:29:04','2024-03-22 01:12:36',1),(1762726594225053697,'A + B','题目内容','[\"栈\",\"简单\"]','暴力破解',0,0,'[{\"input\":\"1 2\",\"output\":\"3 4\"}]','{\"timeLimit\":1000,\"memoryLimit\":1000,\"stackLimit\":1000}',0,0,1759173052197416962,'2024-02-28 14:29:04','2024-03-22 01:12:36',1),(1762726596963934209,'A + B','题目内容','[\"栈\",\"简单\"]','暴力破解',0,0,'[{\"input\":\"1 2\",\"output\":\"3 4\"}]','{\"timeLimit\":1000,\"memoryLimit\":1000,\"stackLimit\":1000}',0,0,1759173052197416962,'2024-02-28 14:29:05','2024-03-22 01:12:36',1),(1762726597559525377,'A + B','题目内容','[\"栈\",\"简单\"]','暴力破解',0,0,'[{\"input\":\"1 2\",\"output\":\"3 4\"}]','{\"timeLimit\":1000,\"memoryLimit\":1000,\"stackLimit\":1000}',0,0,1759173052197416962,'2024-02-28 14:29:05','2024-03-22 01:12:36',1),(1762726598801039361,'B + C','新的问题','[\"二叉树\"]','新的答案',0,0,'[{\"input\":\"新的用例输入\",\"output\":\"新的用例输出\"}]','{\"timeLimit\":300,\"memoryLimit\":100,\"stackLimit\":200}',0,0,1759173052197416962,'2024-02-28 14:29:05','2024-03-22 01:12:36',1),(1763479685283123201,'A + B','题目内容','[\"栈\",\"简单\"]','暴力破解',0,0,'[{\"input\":\"1 2\",\"output\":\"3 4\"}]','{\"timeLimit\":1000,\"memoryLimit\":1000,\"stackLimit\":1000}',0,0,1759173052197416962,'2024-03-01 16:21:35','2024-03-22 01:12:36',1),(1763479869824110594,'A + B','给定一个整数数组 nums 和一个整数目标值 target，请你在该数组中找出 和为目标值 target  的那 两个 整数，并返回它们的数组下标。\n\n你可以假设每种输入只会对应一个答案。但是，数组中同一个元素在答案里不能重复出现。\n\n你可以按任意顺序返回答案。','[\"栈\",\"简单\"]','暴力破解',0,0,'[{\"input\":\"1 2\",\"output\":\"3 4\"}]','{\"timeLimit\":1000,\"memoryLimit\":1000,\"stackLimit\":1000}',0,0,1759173052197416962,'2024-03-01 16:22:19','2024-03-22 01:12:36',1),(1764000139487965186,'两数之和','## **Problem Description**\n\nCalculate *A + B*.\n\n \n\n## **Input**\n\nEach line will contain two integers *A* and *B*. Process to end of file.\n\n \n\n## **Output**\n\nFor each case, output *A + B* in one line.\n\n \n\n## **Sample Input**\n\n```\n1 1\n```\n\n \n\n## **Sample Output**\n\n```\n2\n```\n\n \n\n## **Author**\n\nHDOJ','[\"简单\"]','📖 文字题解\n方法一：暴力枚举\n思路及算法\n\n最容易想到的方法是枚举数组中的每一个数 x，寻找数组中是否存在 target - x。\n\n当我们使用遍历整个数组的方式寻找 target - x 时，需要注意到每一个位于 x 之前的元素都已经和 x 匹配过，因此不需要再进行匹配。而每一个元素不能被使用两次，所以我们只需要在 x 后面的元素中寻找 target - x。\n\n代码\n\n\n```java\npublic class Main {\n\n    public static void main(String[] args) {\n        int a = Integer.parseInt(args[0]);\n        int b = Integer.parseInt(args[1]);\n        System.out.println(a + b);\n    }\n}\n\n```\n复杂度分析\n\n时间复杂度：O(N2)O(N^2)O(N \n2\n )，其中 NNN 是数组中的元素数量。最坏情况下数组中任意两个数都要被匹配一次。\n\n空间复杂度：O(1)O(1)O(1)。\n\n方法二：哈希表\n思路及算法\n\n注意到方法一的时间复杂度较高的原因是寻找 target - x 的时间复杂度过高。因此，我们需要一种更优秀的方法，能够快速寻找数组中是否存在目标元素。如果存在，我们需要找出它的索引。\n\n使用哈希表，可以将寻找 target - x 的时间复杂度降低到从 O(N)O(N)O(N) 降低到 O(1)O(1)O(1)。\n\n这样我们创建一个哈希表，对于每一个 x，我们首先查询哈希表中是否存在 target - x，然后将 x 插入到哈希表中，即可保证不会让 x 和自己匹配。\n',13,0,'[{\"input\":\"1 1\",\"output\":\"2\"},{\"input\":\"2 2\",\"output\":\"4\"},{\"input\":\"3 3\",\"output\":\"6\"},{\"input\":\"100 100\",\"output\":\"200\"}]','{\"timeLimit\":300000,\"memoryLimit\":2000000,\"stackLimit\":1000}',0,5,1759173052197416962,'2024-03-03 02:49:41','2024-06-18 16:56:01',0),(1766066231068794882,'回文数','## **Problem Description**\n\n给你一个整数 `x` ，如果 `x` 是一个回文整数，返回 `true` ；否则，返回 `false` 。\n\n`回文数`是指正序（从左向右）和倒序（从右向左）读都是一样的整数。\n\n- 例如，`121` 是回文，而 `123` 不是。\n\n \n\n**示例 1：**\n\n```\n输入：x = 121\n输出：true\n```\n\n**示例 2：**\n\n```\n输入：x = -121\n输出：false\n解释：从左向右读, 为 -121 。 从右向左读, 为 121- 。因此它不是一个回文数。\n```\n\n**示例 3：**\n\n```\n输入：x = 10\n输出：false\n解释：从右向左读, 为 01 。因此它不是一个回文数。\n```\n\n','[\"简单\"]','```java\npublic class Main {\n    public static boolean isPalindrome(int x) {\n        if (x < 0 || (x % 10 == 0 && x != 0)) {\n            return false;\n        }\n\n        int revertedNumber = 0;\n        while (x > revertedNumber) {\n            revertedNumber = revertedNumber * 10 + x % 10;\n            x /= 10;\n        }\n        return x == revertedNumber || x == revertedNumber / 10;\n    }\n\n    public static void main(String[] args) {\n        int x = Integer.parseInt(args[0]);\n        System.out.println(isPalindrome(x));\n    }\n}\n```\n',7,3,'[{\"input\":\"232\",\"output\":\"true\"},{\"input\":\"-112\",\"output\":\"false\"},{\"input\":\"6776\",\"output\":\"true\"}]','{\"timeLimit\":2000,\"memoryLimit\":10000000,\"stackLimit\":1000}',0,3,1759173052197416962,'2024-03-08 19:39:36','2024-04-17 23:08:25',0),(1766076867161079810,'罗马数字转整数','## **Problem Description**\n\n罗马数字包含以下七种字符: `I`， `V`， `X`， `L`，`C`，`D` 和 `M`。\n\n```\n字符          数值\nI             1\nV             5\nX             10\nL             50\nC             100\nD             500\nM             1000\n```\n\n例如， 罗马数字 `2` 写做 `II` ，即为两个并列的 1 。`12` 写做 `XII` ，即为 `X` + `II` 。 `27` 写做 `XXVII`, 即为 `XX` + `V` + `II` 。\n\n通常情况下，罗马数字中小的数字在大的数字的右边。但也存在特例，例如 4 不写做 `IIII`，而是 `IV`。数字 1 在数字 5 的左边，所表示的数等于大数 5 减小数 1 得到的数值 4 。同样地，数字 9 表示为 `IX`。这个特殊的规则只适用于以下六种情况：\n\n- `I` 可以放在 `V` (5) 和 `X` (10) 的左边，来表示 4 和 9。\n- `X` 可以放在 `L` (50) 和 `C` (100) 的左边，来表示 40 和 90。 \n- `C` 可以放在 `D` (500) 和 `M` (1000) 的左边，来表示 400 和 900。\n\n给定一个罗马数字，将其转换成整数。\n\n \n\n**示例 1:**\n\n```\n输入: s = \"III\"\n输出: 3\n```\n\n**示例 2:**\n\n```\n输入: s = \"IV\"\n输出: 4\n```\n\n**示例 3:**\n\n```\n输入: s = \"IX\"\n输出: 9\n```\n\n**示例 4:**\n\n```\n输入: s = \"LVIII\"\n输出: 58\n解释: L = 50, V= 5, III = 3.\n```\n\n**示例 5:**\n\n```\n输入: s = \"MCMXCIV\"\n输出: 1994\n解释: M = 1000, CM = 900, XC = 90, IV = 4.\n```\n\n \n\n**提示：**\n\n- `1 <= s.length <= 15`\n- `s` 仅含字符 `(\'I\', \'V\', \'X\', \'L\', \'C\', \'D\', \'M\')`\n- 题目数据保证 `s` 是一个有效的罗马数字，且表示整数在范围 `[1, 3999]` 内\n- 题目所给测试用例皆符合罗马数字书写规则，不会出现跨位等情况。\n- IL 和 IM 这样的例子并不符合题目要求，49 应该写作 XLIX，999 应该写作 CMXCIX 。\n- 关于罗马数字的详尽书写规则，可以参考 [罗马数字 - Mathematics ](https://b2b.partcommunity.com/community/knowledge/zh_CN/detail/10753/罗马数字#knowledge_article)。','[\"简单\"]','```java\nimport java.util.HashMap;\nimport java.util.Map;\n\npublic class Main {\n    static Map<Character, Integer> symbolValues = new HashMap<Character, Integer>() {{\n        put(\'I\', 1);\n        put(\'V\', 5);\n        put(\'X\', 10);\n        put(\'L\', 50);\n        put(\'C\', 100);\n        put(\'D\', 500);\n        put(\'M\', 1000);\n    }};\n\n    public static int romanToInt(String s) {\n        int ans = 0;\n        int n = s.length();\n        for (int i = 0; i < n; ++i) {\n            int value = symbolValues.get(s.charAt(i));\n            if (i < n - 1 && value < symbolValues.get(s.charAt(i + 1))) {\n                ans -= value;\n            } else {\n                ans += value;\n            }\n        }\n        return ans;\n    }\n\n    public static void main(String[] args){\n        System.out.println(romanToInt(args[0]));\n    }\n}\n```\n',3,3,'[{\"input\":\"III\",\"output\":\"3\"},{\"input\":\"IV\",\"output\":\"4\"},{\"input\":\"IX\",\"output\":\"9\"},{\"input\":\"LVIII\",\"output\":\"58\"},{\"input\":\"MCMXCIV\",\"output\":\"1994\"}]','{\"timeLimit\":2000,\"memoryLimit\":30000000,\"stackLimit\":1000}',0,2,1759173052197416962,'2024-03-08 20:21:51','2024-04-17 21:06:02',0),(1766081158135398402,'寻找两个正序数组的中位数','## **Problem Description**\n\n给定两个大小分别为 `m` 和 `n` 的正序（从小到大）数组 `nums1` 和 `nums2`。请你找出并返回这两个正序数组的 **中位数** 。\n\n算法的时间复杂度应该为 `O(log (m+n))` 。\n\n \n\n**示例 1：**\n\n```\n输入：nums1 = [1,3], nums2 = [2]\n输出：2.00000\n解释：合并数组 = [1,2,3] ，中位数 2\n```\n\n**示例 2：**\n\n```\n输入：nums1 = [1,2], nums2 = [3,4]\n输出：2.50000\n解释：合并数组 = [1,2,3,4] ，中位数 (2 + 3) / 2 = 2.5\n```\n\n\n\n**提示：**\n\n- `nums1.length == m`\n- `nums2.length == n`\n- `0 <= m <= 1000`\n- `0 <= n <= 1000`\n- `1 <= m + n <= 2000`\n- `-106 <= nums1[i], nums2[i] <= 106`','[\"困难\",\"二分查找\"]','```java\npublic class Main {\n    public static double findMedianSortedArrays(int[] nums1, int[] nums2) {\n        int length1 = nums1.length, length2 = nums2.length;\n        int totalLength = length1 + length2;\n        if (totalLength % 2 == 1) {\n            int midIndex = totalLength / 2;\n            double median = getKthElement(nums1, nums2, midIndex + 1);\n            return median;\n        } else {\n            int midIndex1 = totalLength / 2 - 1, midIndex2 = totalLength / 2;\n            double median = (getKthElement(nums1, nums2, midIndex1 + 1) + getKthElement(nums1, nums2, midIndex2 + 1)) / 2.0;\n            return median;\n        }\n    }\n\n    public static int getKthElement(int[] nums1, int[] nums2, int k) {\n        /* 主要思路：要找到第 k (k>1) 小的元素，那么就取 pivot1 = nums1[k/2-1] 和 pivot2 = nums2[k/2-1] 进行比较\n         * 这里的 \"/\" 表示整除\n         * nums1 中小于等于 pivot1 的元素有 nums1[0 .. k/2-2] 共计 k/2-1 个\n         * nums2 中小于等于 pivot2 的元素有 nums2[0 .. k/2-2] 共计 k/2-1 个\n         * 取 pivot = min(pivot1, pivot2)，两个数组中小于等于 pivot 的元素共计不会超过 (k/2-1) + (k/2-1) <= k-2 个\n         * 这样 pivot 本身最大也只能是第 k-1 小的元素\n         * 如果 pivot = pivot1，那么 nums1[0 .. k/2-1] 都不可能是第 k 小的元素。把这些元素全部 \"删除\"，剩下的作为新的 nums1 数组\n         * 如果 pivot = pivot2，那么 nums2[0 .. k/2-1] 都不可能是第 k 小的元素。把这些元素全部 \"删除\"，剩下的作为新的 nums2 数组\n         * 由于我们 \"删除\" 了一些元素（这些元素都比第 k 小的元素要小），因此需要修改 k 的值，减去删除的数的个数\n         */\n\n        int length1 = nums1.length, length2 = nums2.length;\n        int index1 = 0, index2 = 0;\n        int kthElement = 0;\n\n        while (true) {\n            // 边界情况\n            if (index1 == length1) {\n                return nums2[index2 + k - 1];\n            }\n            if (index2 == length2) {\n                return nums1[index1 + k - 1];\n            }\n            if (k == 1) {\n                return Math.min(nums1[index1], nums2[index2]);\n            }\n\n            // 正常情况\n            int half = k / 2;\n            int newIndex1 = Math.min(index1 + half, length1) - 1;\n            int newIndex2 = Math.min(index2 + half, length2) - 1;\n            int pivot1 = nums1[newIndex1], pivot2 = nums2[newIndex2];\n            if (pivot1 <= pivot2) {\n                k -= (newIndex1 - index1 + 1);\n                index1 = newIndex1 + 1;\n            } else {\n                k -= (newIndex2 - index2 + 1);\n                index2 = newIndex2 + 1;\n            }\n        }\n    }\n    public static void main(String[] args){\n        // 解析第一个数组\n        String[] array1Strings = args[0].split(\",\");\n        int[] array1 = new int[array1Strings.length];\n        for (int i = 0; i < array1Strings.length; i++) {\n            array1[i] = Integer.parseInt(array1Strings[i]);\n        }\n\n        // 解析第二个数组\n        String[] array2Strings = args[1].split(\",\");\n        int[] array2 = new int[array2Strings.length];\n        for (int i = 0; i < array2Strings.length; i++) {\n            array2[i] = Integer.parseInt(array2Strings[i]);\n        }\n        System.out.println(findMedianSortedArrays(array1, array2));\n    }\n}\n```\n',10,9,'[{\"input\":\"1,3 2\",\"output\":\"2.0\"},{\"input\":\"1,2 3,4\",\"output\":\"2.5\"}]','{\"timeLimit\":3000,\"memoryLimit\":30000000,\"stackLimit\":1000}',0,2,1759173052197416962,'2024-03-08 20:38:54','2024-04-18 12:52:26',0),(1766087396260823041,'dsd','a','[\"困难\"]','a',0,0,'[{\"input\":\"a\",\"output\":\"a\"}]','{\"timeLimit\":1000,\"memoryLimit\":1000,\"stackLimit\":1000}',0,0,1759173052197416962,'2024-03-08 21:03:42','2024-03-22 01:12:39',1),(1766095706234011650,'ds','d','[\"一般\"]','d',0,0,'[{\"input\":\"d\",\"output\":\"d\"}]','{\"timeLimit\":1000,\"memoryLimit\":1000,\"stackLimit\":1000}',0,0,1759173052197416962,'2024-03-08 21:36:43','2024-03-22 01:12:39',1),(1766097295648735233,'d','d','[]','d',0,0,'[{\"input\":\"d\",\"output\":\"d\"}]','{\"timeLimit\":1000,\"memoryLimit\":1000,\"stackLimit\":1000}',0,0,1759173052197416962,'2024-03-08 21:43:02','2024-03-22 01:12:39',1),(1770541838427144193,'测试','测试','[\"测试\"]','测试',0,0,'[{\"input\":\"1\",\"output\":\"1\"}]','{\"timeLimit\":1000,\"memoryLimit\":1000,\"stackLimit\":1000}',0,0,1759173052197416962,'2024-03-21 04:04:04','2024-03-28 21:56:53',1),(1776473409843802113,'1','1','[\"1\"]','1',0,0,'[{\"input\":\"\",\"output\":\"\"}]','{\"timeLimit\":1000,\"memoryLimit\":1000,\"stackLimit\":1000}',0,0,1759173052197416962,'2024-04-06 12:54:00','2024-04-06 12:55:54',1),(1776473557755932674,'1','1','[\"1\"]','1',0,0,'[{\"input\":\"q\",\"output\":\"q\"}]','{\"timeLimit\":1000,\"memoryLimit\":1000,\"stackLimit\":1000}',0,0,1759173052197416962,'2024-04-06 12:54:36','2024-04-06 12:55:55',1),(1776473613254963202,'1','1','[\"1\"]','',0,0,'[{\"input\":\"q\",\"output\":\"q\"}]','{\"timeLimit\":1000,\"memoryLimit\":1000,\"stackLimit\":1000}',0,0,1759173052197416962,'2024-04-06 12:54:49','2024-04-06 12:55:56',1),(1777086799129862145,'合并两个有序链表','将两个升序链表合并为一个新的 **升序** 链表并返回。新链表是通过拼接给定的两个链表的所有节点组成的。 \n\n \n\n**示例 1：**\n\n![img](https://assets.leetcode.com/uploads/2020/10/03/merge_ex1.jpg)\n\n```\n输入：l1 = [1,2,4], l2 = [1,3,4]\n输出：[1,1,2,3,4,4]\n```\n\n**示例 2：**\n\n```\n输入：l1 = [], l2 = []\n输出：[]\n```\n\n**示例 3：**\n\n```\n输入：l1 = [], l2 = [0]\n输出：[0]\n```\n\n \n\n**提示：**\n\n- 两个链表的节点数目范围是 `[0, 50]`\n- `-100 <= Node.val <= 100`\n- `l1` 和 `l2` 均按 **非递减顺序** 排列','[\"递归\",\"链表\",\"一般\"]','📖 文字题解\n方法一：递归\n思路\n\n我们可以如下递归地定义两个链表里的 merge 操作（忽略边界情况，比如空链表等）：\n\n{list1[0]+merge(list1[1:],list2)list1[0]<list2[0]list2[0]+merge(list1,list2[1:])otherwise\\left\\{ \\begin{array}{ll} list1[0] + merge(list1[1:], list2) & list1[0] < list2[0] \\\\ list2[0] + merge(list1, list2[1:]) & otherwise \\end{array} \\right.\n{ \nlist1[0]+merge(list1[1:],list2)\nlist2[0]+merge(list1,list2[1:])\n​\n  \nlist1[0]<list2[0]\notherwise\n​\n \n也就是说，两个链表头部值较小的一个节点与剩下元素的 merge 操作结果合并。\n\n算法\n\n我们直接将以上递归过程建模，同时需要考虑边界情况。\n\n如果 l1 或者 l2 一开始就是空链表 ，那么没有任何操作需要合并，所以我们只需要返回非空链表。否则，我们要判断 l1 和 l2 哪一个链表的头节点的值更小，然后递归地决定下一个添加到结果里的节点。如果两个链表有一个为空，递归结束。\n\n\n```java\nclass Solution {\n    public ListNode mergeTwoLists(ListNode l1, ListNode l2) {\n        if (l1 == null) {\n            return l2;\n        } else if (l2 == null) {\n            return l1;\n        } else if (l1.val < l2.val) {\n            l1.next = mergeTwoLists(l1.next, l2);\n            return l1;\n        } else {\n            l2.next = mergeTwoLists(l1, l2.next);\n            return l2;\n        }\n    }\n}\n\n```',1,0,'[{\"input\":\"[], []\",\"output\":\"[]\"},{\"input\":\"[1,2,4],[1,3,4]\",\"output\":\"[1,1,2,3,4,4]\"}]','{\"timeLimit\":1000,\"memoryLimit\":1000,\"stackLimit\":1000}',0,1,1759173052197416962,'2024-04-08 05:31:24','2024-04-18 11:24:32',0),(1777087308981067777,'最后一个单词的长度','给你一个字符串 `s`，由若干单词组成，单词前后用一些空格字符隔开。返回字符串中 **最后一个** 单词的长度。\n\n**单词** 是指仅由字母组成、不包含任何空格字符的最大\n\n子字符串\n\n。\n\n\n\n \n\n**示例 1：**\n\n```\n输入：s = \"Hello World\"\n输出：5\n解释：最后一个单词是“World”，长度为5。\n```\n\n**示例 2：**\n\n```\n输入：s = \"   fly me   to   the moon  \"\n输出：4\n解释：最后一个单词是“moon”，长度为4。\n```\n\n**示例 3：**\n\n```\n输入：s = \"luffy is still joyboy\"\n输出：6\n解释：最后一个单词是长度为6的“joyboy”。\n```\n\n \n\n**提示：**\n\n- `1 <= s.length <= 104`\n- `s` 仅有英文字母和空格 `\' \'` 组成\n- `s` 中至少存在一个单词','[\"字符串\"]','方法一：反向遍历\n题目要求得到字符串中最后一个单词的长度，可以反向遍历字符串，寻找最后一个单词并计算其长度。\n\n由于字符串中至少存在一个单词，因此字符串中一定有字母。首先找到字符串中的最后一个字母，该字母即为最后一个单词的最后一个字母。\n\n从最后一个字母开始继续反向遍历字符串，直到遇到空格或者到达字符串的起始位置。遍历到的每个字母都是最后一个单词中的字母，因此遍历到的字母数量即为最后一个单词的长度。\n\n```java\nclass Solution {\n    public int lengthOfLastWord(String s) {\n        int index = s.length() - 1;\n        while (s.charAt(index) == \' \') {\n            index--;\n        }\n        int wordLength = 0;\n        while (index >= 0 && s.charAt(index) != \' \') {\n            wordLength++;\n            index--;\n        }\n        return wordLength;\n    }\n}\n```\n复杂度分析\n\n',0,0,'[{\"input\":\"fdsfd fds\",\"output\":\"3\"}]','{\"timeLimit\":1000,\"memoryLimit\":1000,\"stackLimit\":1000}',0,0,1759173052197416962,'2024-04-08 05:33:25','2024-04-08 05:33:25',0),(1777088384174120962,'爬楼梯','- - - 假设你正在爬楼梯。需要 `n` 阶你才能到达楼顶。\n\n      每次你可以爬 `1` 或 `2` 个台阶。你有多少种不同的方法可以爬到楼顶呢？\n\n       \n\n      **示例 1：**\n\n      ```\n      输入：n = 2\n      输出：2\n      解释：有两种方法可以爬到楼顶。\n      1. 1 阶 + 1 阶\n      2. 2 阶\n      ```\n\n      **示例 2：**\n\n      ```\n      输入：n = 3\n      输出：3\n      解释：有三种方法可以爬到楼顶。\n      1. 1 阶 + 1 阶 + 1 阶\n      2. 1 阶 + 2 阶\n      3. 2 阶 + 1 阶\n      ```\n\n','[\"记忆化搜索\",\"数学\",\"动态规划\",\"一般\"]','方法一：动态规划\n思路和算法\n\n我们用 f(x)f(x)f(x) 表示爬到第 xxx 级台阶的方案数，考虑最后一步可能跨了一级台阶，也可能跨了两级台阶，所以我们可以列出如下式子：\n\nf(x)=f(x−1)+f(x−2)f(x) = f(x - 1) + f(x - 2)f(x)=f(x−1)+f(x−2)\n\n它意味着爬到第 xxx 级台阶的方案数是爬到第 x−1x - 1x−1 级台阶的方案数和爬到第 x−2x - 2x−2 级台阶的方案数的和。很好理解，因为每次只能爬 111 级或 222 级，所以 f(x)f(x)f(x) 只能从 f(x−1)f(x - 1)f(x−1) 和 f(x−2)f(x - 2)f(x−2) 转移过来，而这里要统计方案总数，我们就需要对这两项的贡献求和。\n\n以上是动态规划的转移方程，下面我们来讨论边界条件。我们是从第 000 级开始爬的，所以从第 000 级爬到第 000 级我们可以看作只有一种方案，即 f(0)=1f(0) = 1f(0)=1；从第 000 级到第 111 级也只有一种方案，即爬一级，f(1)=1f(1) = 1f(1)=1。这两个作为边界条件就可以继续向后推导出第 nnn 级的正确结果。我们不妨写几项来验证一下，根据转移方程得到 f(2)=2f(2) = 2f(2)=2，f(3)=3f(3) = 3f(3)=3，f(4)=5f(4) = 5f(4)=5，……，我们把这些情况都枚举出来，发现计算的结果是正确的。\n\n我们不难通过转移方程和边界条件给出一个时间复杂度和空间复杂度都是 O(n)O(n)O(n) 的实现，但是由于这里的 f(x)f(x)f(x) 只和 f(x−1)f(x - 1)f(x−1) 与 f(x−2)f(x - 2)f(x−2) 有关，所以我们可以用「滚动数组思想」把空间复杂度优化成 O(1)O(1)O(1)。下面的代码中给出的就是这种实现。\n\n![Alt](https://assets.leetcode-cn.com/solution-static/70/70_fig1.gif)\n\n**代码**\n\n```java\nclass Solution {\n    public int climbStairs(int n) {\n        int p = 0, q = 0, r = 1;\n        for (int i = 1; i <= n; ++i) {\n            p = q; \n            q = r; \n            r = p + q;\n        }\n        return r;\n    }\n}\n```\n\n复杂度分析\n\n时间复杂度：循环执行 nnn 次，每次花费常数的时间代价，故渐进时间复杂度为 O(n)O(n)O(n)。\n空间复杂度：这里只用了常数个变量作为辅助空间，故渐进空间复杂度为 O(1)O(1)O(1)。',0,0,'[{\"input\":\"1 2\",\"output\":\"3 4\"}]','{\"timeLimit\":1000,\"memoryLimit\":1000,\"stackLimit\":1000}',0,0,1759173052197416962,'2024-04-08 05:37:42','2024-04-08 05:52:28',0),(1777090631276683266,'将有序数组转换为二叉搜索树','给你一个整数数组 `nums` ，其中元素已经按 **升序** 排列，请你将其转换为一棵 \n\n平衡\n\n 二叉搜索树。\n\n\n\n \n\n**示例 1：**\n\n![img](https://assets.leetcode.com/uploads/2021/02/18/btree1.jpg)\n\n```\n输入：nums = [-10,-3,0,5,9]\n输出：[0,-3,9,-10,null,5]\n解释：[0,-10,5,null,-3,null,9] 也将被视为正确答案：\n```\n\n**示例 2：**\n\n![img](https://assets.leetcode.com/uploads/2021/02/18/btree.jpg)\n\n```\n输入：nums = [1,3]\n输出：[3,1]\n解释：[1,null,3] 和 [3,1] 都是高度平衡二叉搜索树。\n```\n\n \n\n**提示：**\n\n- `1 <= nums.length <= 104`\n- `-104 <= nums[i] <= 104`\n- `nums` 按 **严格递增** 顺序排列','[\"树\",\"二叉搜索树\",\"数组\",\"分治\",\"二叉树\",\"困难\"]','📖 文字题解\n前言\n二叉搜索树的中序遍历是升序序列，题目给定的数组是按照升序排序的有序数组，因此可以确保数组是二叉搜索树的中序遍历序列。\n\n给定二叉搜索树的中序遍历，是否可以唯一地确定二叉搜索树？答案是否定的。如果没有要求二叉搜索树的高度平衡，则任何一个数字都可以作为二叉搜索树的根节点，因此可能的二叉搜索树有多个。\n\n\n\n![Alt](https://assets.leetcode-cn.com/solution-static/108/108_fig1.png)\n\n\n\n如果增加一个限制条件即要求二叉搜索树的高度平衡，是否可以唯一地确定二叉搜索树？答案仍然是否定的。\n\n![ALT](https://assets.leetcode-cn.com/solution-static/108/108_fig2.png)\n\n直观地看，我们可以选择中间数字作为二叉搜索树的根节点，这样分给左右子树的数字个数相同或只相差 111，可以使得树保持平衡。如果数组长度是奇数，则根节点的选择是唯一的，如果数组长度是偶数，则可以选择中间位置左边的数字作为根节点或者选择中间位置右边的数字作为根节点，选择不同的数字作为根节点则创建的平衡二叉搜索树也是不同的。\n\n![ALT](https://assets.leetcode-cn.com/solution-static/108/108_fig3.png)\n\n确定平衡二叉搜索树的根节点之后，其余的数字分别位于平衡二叉搜索树的左子树和右子树中，左子树和右子树分别也是平衡二叉搜索树，因此可以通过递归的方式创建平衡二叉搜索树。\n\n当然，这只是我们直观的想法，为什么这么建树一定能保证是「平衡」的呢？这里可以参考「1382. 将二叉搜索树变平衡」，这两道题的构造方法完全相同，这种方法是正确的，1382 题解中给出了这个方法的正确性证明：1382 官方题解，感兴趣的同学可以戳进去参考。\n\n递归的基准情形是平衡二叉搜索树不包含任何数字，此时平衡二叉搜索树为空。\n\n在给定中序遍历序列数组的情况下，每一个子树中的数字在数组中一定是连续的，因此可以通过数组下标范围确定子树包含的数字，下标范围记为 [left,right][\\textit{left}, \\textit{right}][left,right]。对于整个中序遍历序列，下标范围从 left=0\\textit{left}=0left=0 到 right=nums.length−1\\textit{right}=\\textit{nums}.\\text{length}-1right=nums.length−1。当 left>right\\textit{left}>\\textit{right}left>right 时，平衡二叉搜索树为空。\n\n以下三种方法中，方法一总是选择中间位置左边的数字作为根节点，方法二总是选择中间位置右边的数字作为根节点，方法三是方法一和方法二的结合，选择任意一个中间位置数字作为根节点。',0,0,'[{\"input\":\"1 2\",\"output\":\"3 4\"}]','{\"timeLimit\":1000,\"memoryLimit\":1000,\"stackLimit\":1000}',0,0,1759173052197416962,'2024-04-08 05:46:37','2024-04-08 05:51:57',0),(1777091480849735682,'杨辉三角','给定一个非负整数 *`numRows`，*生成「杨辉三角」的前 *`numRows`* 行。\n\n在「杨辉三角」中，每个数是它左上方和右上方的数的和。\n\n![img](https://pic.leetcode-cn.com/1626927345-DZmfxB-PascalTriangleAnimated2.gif)\n\n \n\n**示例 1:**\n\n```\n输入: numRows = 5\n输出: [[1],[1,1],[1,2,1],[1,3,3,1],[1,4,6,4,1]]\n```\n\n**示例 2:**\n\n```\n输入: numRows = 1\n输出: [[1]]\n```\n\n \n\n**提示:**\n\n- `1 <= numRows <= 30`','[\"数组\",\"动态规划\",\"困难\"]','```JAVA\nclass Solution {\n    public List<List<Integer>> generate(int numRows) {\n        List<List<Integer>> ret = new ArrayList<List<Integer>>();\n        for (int i = 0; i < numRows; ++i) {\n            List<Integer> row = new ArrayList<Integer>();\n            for (int j = 0; j <= i; ++j) {\n                if (j == 0 || j == i) {\n                    row.add(1);\n                } else {\n                    row.add(ret.get(i - 1).get(j - 1) + ret.get(i - 1).get(j));\n                }\n            }\n            ret.add(row);\n        }\n        return ret;\n    }\n}\n\n```',4,0,'[{\"input\":\"23 43\",\"output\":\"32\"}]','{\"timeLimit\":1000,\"memoryLimit\":1000,\"stackLimit\":1000}',0,2,1759173052197416962,'2024-04-08 05:50:00','2025-03-19 08:20:04',0),(1780542670287613953,'两数之和（二）','## 这是题目内容\n## 这是题目内容\n## 这是题目内容','[\"困难\"]','## 这是题目答案\n## 这是题目答案\n## 这是题目答案',0,0,'[{\"input\":\"1 2\",\"output\":\"3\"},{\"input\":\"2 3\",\"output\":\"5\"}]','{\"timeLimit\":1000,\"memoryLimit\":1000,\"stackLimit\":1000}',0,0,1759173052197416962,'2024-04-17 18:23:48','2024-04-17 18:33:51',1),(1780799669466251265,'s','c','[\"s\"]','c',0,0,'[{\"input\":\"1 2\",\"output\":\"3\"}]','{\"timeLimit\":1000,\"memoryLimit\":1000,\"stackLimit\":1000}',0,0,1759173052197416962,'2024-04-18 11:25:01','2024-04-18 11:25:14',1);
