    }\r\n}\r\n','{\"message\":\"Accepted\",\"memory\":1499136,\"time\":222}',2,1764000139487965186,1759173052197416962,'2024-03-08 19:31:11','2024-03-08 19:31:12',0),(1766066422794625025,'java','class Main {\r\n    public boolean isPalindrome(int x) {\r\n        // 特殊情况：\r\n        // 如上所述，当 x < 0 时，x 不是回文数。\r\n        // 同样地，如果数字的最后一位是 0，为了使该数字为回文，\r\n        // 则其第一位数字也应该是 0\r\n        // 只有 0 满足这一属性\r\n        if (x < 0 || (x % 10 == 0 && x != 0)) {\r\n            return false;\r\n        }\r\n\r\n        int revertedNumber = 0;\r\n        while (x > revertedNumber) {\r\n            revertedNumber = revertedNumber * 10 + x % 10;\r\n            x /= 10;\r\n        }\r\n\r\n        // 当数字长度为奇数时，我们可以通过 revertedNumber/10 去除处于中位的数字。\r\n        // 例如，当输入为 12321 时，在 while 循环的末尾我们可以得到 x = 12，revertedNumber = 123，\r\n        // 由于处于中位的数字不影响回文（它总是与自己相等），所以我们可以简单地将其去除。\r\n        return x == revertedNumber || x == revertedNumber / 10;\r\n    }\r\n}','{\"message\":\"Wrong Answer\",\"memory\":1859584,\"time\":254}',2,1766066231068794882,1759173052197416962,'2024-03-08 19:40:21','2024-03-08 19:40:23',0),(1766066708045045761,'java','class Main {\r\n    public boolean isPalindrome(int x) {\r\n        // 特殊情况：\r\n        // 如上所述，当 x < 0 时，x 不是回文数。\r\n        // 同样地，如果数字的最后一位是 0，为了使该数字为回文，\r\n        // 则其第一位数字也应该是 0\r\n        // 只有 0 满足这一属性\r\n        if (x < 0 || (x % 10 == 0 && x != 0)) {\r\n            return false;\r\n        }\r\n\r\n        int revertedNumber = 0;\r\n        while (x > revertedNumber) {\r\n            revertedNumber = revertedNumber * 10 + x % 10;\r\n            x /= 10;\r\n        }\r\n\r\n        // 当数字长度为奇数时，我们可以通过 revertedNumber/10 去除处于中位的数字。\r\n        // 例如，当输入为 12321 时，在 while 循环的末尾我们可以得到 x = 12，revertedNumber = 123，\r\n        // 由于处于中位的数字不影响回文（它总是与自己相等），所以我们可以简单地将其去除。\r\n        return x == revertedNumber || x == revertedNumber / 10;\r\n    }\r\n}','{}',1,1766066231068794882,1759173052197416962,'2024-03-08 19:41:29','2024-03-22 05:22:01',1),(17660