1 = nums1.length, length2 = nums2.length;\r\n        int index1 = 0, index2 = 0;\r\n        int kthElement = 0;\r\n\r\n        while (true) {\r\n            // 边界情况\r\n            if (index1 == length1) {\r\n                return nums2[index2 + k - 1];\r\n            }\r\n            if (index2 == length2) {\r\n                return nums1[index1 + k - 1];\r\n            }\r\n            if (k == 1) {\r\n                return Math.min(nums1[index1], nums2[index2]);\r\n            }\r\n\r\n            // 正常情况\r\n            int half = k / 2;\r\n            int newIndex1 = Math.min(index1 + half, length1) - 1;\r\n            int newIndex2 = Math.min(index2 + half, length2) - 1;\r\n            int pivot1 = nums1[newIndex1], pivot2 = nums2[newIndex2];\r\n            if (pivot1 <= pivot2) {\r\n                k -= (newIndex1 - index1 + 1);\r\n                index1 = newIndex1 + 1;\r\n            } else {\r\n                k -= (newIndex2 - index2 + 1);\r\n                index2 = newIndex2 + 1;\r\n            }\r\n        }\r\n    }\r\n    public static void main(String[] args){\r\n        // 解析第一个数组\r\n        String[] array1Strings = args[0].split(\",\");\r\n        int[] array1 = new int[array1Strings.length];\r\n        for (int i = 0; i < array1Strings.length; i++) {\r\n            array1[i] = Integer.parseInt(array1Strings[i]);\r\n        }\r\n\r\n        // 解析第二个数组\r\n        String[] array2Strings = args[1].split(\",\");\r\n        int[] array2 = new int[array2Strings.length];\r\n        for (int i = 0; i < array2Strings.length; i++) {\r\n            array2[i] = Integer.parseInt(array2Strings[i]);\r\n        }\r\n        System.out.println(findMedianSortedArrays(array1, array2));\r\n    }\r\n}','{\"message\":\"Accepted\",\"memory\":1777664,\"time\":417}',2,1766081158135398402,1759173052197416962,'2024-04-18 12:52:24','2024-04-18 12:52:26',0),(1787721554095493121,'java','class Solution {\r\n    public List<List<Integer>> generate(int numRows) {\r\n        List<List<Integer>> ret = new ArrayList<List<Integer>>();\r\n        for (int i = 0; i < numRows; ++i) {\r\n            List<Integer> row = new ArrayList<Integer>();\r\n            for (int j = 0; j <= i; ++j) {\r\n                if (j == 0 || j == i) {\r\n                    row.add(1);\r\n                } else {\r\n                    row.add(ret.get(i - 1).get(j - 1) + ret.get(i - 1).get(j));\r\n                }\r\n            }\r\n            ret.add(row);\r\n        }\r\n        return ret;\r\n    }\r\n}','{\"message\":\"Compile Error\",\"memory\":0,\"time\":0}',3,1777091480849735682,1759173052197416962,'2024-05-07 13:50:07','2024-05-07 13:50:09',0),(1802988585329815554,'java','public class Main {\r\n\r\n    public static void main(String[] args) {\r\n        int a = Integer.parseInt(args[0]);\r\n        int b = Integer.parseInt(args[1]);\r\n        System.out.println(a + b);\r\n    }\r\n}','{\"message\":\"Memory Limit Exceeded\",\"memory\":6037504,\"time\":516}',2,1764000139487965186,1780541297311559681,'2024-06-18 16:55:51','2024-06-18 16:55:58',0),(1802988586697158657,'java','public class Main {\r\n\r\n    public static void main(String[] args) {\r\n        int a = Integer.parseInt(args[0]);\r\n        int b = Integer.parseInt(args[1]);\r\n        System.out.println(a + b);\r\n    }\r\n}','{\"message\":\"Memory Limit Exceeded\",\"memory\":15192064,\"time\":481}',2,1764000139487965186,1780541297311559681,'2024-06-18 16:55:51','2024-06-18 16:55:58',0),(1802988617768562690,'java','public class Main {\r\n\r\n    public static void main(String[] args) {\r\n        int a = Integer.parseInt(args[0]);\r\n        int b = Integer.parseInt(args[1]);\r\n        System.out.println(a + b);\r\n    }\r\n}\r\n','{\"message\":\"Memory Limit Exceeded\",\"memory\":10510336,\"time\":339}',2,1764000139487965186,1780541297311559681,'2024-06-18 16:55:59','2024-06-18 16:56:01',0);
