CREATE TABLE `treatment_cards` (
  `card_id` int NOT NULL COMMENT '卡片编号',
  `patient_name` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `diagnosis_type` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `diagnosis_detail` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `session_count` int DEFAULT NULL,
  `open_date` datetime DEFAULT NULL,
  `entry_time` datetime DEFAULT NULL,
  `treatment_text` text COLLATE utf8mb4_unicode_ci,
  `is_herbal_steam` tinyint DEFAULT '0',
  `is_medium_freq` tinyint DEFAULT '0',
  `is_low_freq` tinyint DEFAULT '0',
  `is_guasha` tinyint DEFAULT '0',
  `is_weifaguang` tinyint DEFAULT '0',
  `is_microwave` tinyint DEFAULT '0',
  `is_massage` tinyint DEFAULT '0',
  `is_cupping` tinyint DEFAULT '0',
  `is_electroacupuncture` tinyint DEFAULT '0',
  `is_infrared` tinyint DEFAULT '0',
  `is_acupuncture` tinyint DEFAULT '0',
  PRIMARY KEY (`card_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
