CREATE TABLE `associationrule` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '规则ID',
  `antecedent` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '前项技能组合(技能ID列表，逗号分隔)',
  `consequent` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '后项(如"success"或"failure")',
