--
-- Table structure for table `certificate`
--

DROP TABLE IF EXISTS `certificate`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `certificate` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '证书ID',
  `userId` bigint DEFAULT NULL COMMENT '人员ID，关联User表',
  `skillId` bigint DEFAULT NULL COMMENT '关联技能ID，关联Skill表',
  `certificateNo` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '证书编号',
  `certificateName` varchar(200) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '证书名称',
  `issuingAuthority` varchar(200) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '发证机构',
  `issueDate` date DEFAULT NULL COMMENT '发证日期',
  `expireDate` date DEFAULT NULL COMMENT '有效期至',
  `status` tinyint NOT NULL DEFAULT '1' COMMENT '状态(0-过期,1-有效)',
  `attachment` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '附件路径',
  `createTime` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updateTime` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `isDelete` tinyint NOT NULL DEFAULT '0' COMMENT '逻辑删除(0-正常,1-删除)',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_certificateNo` (`certificateNo`),
  KEY `idx_user` (`userId`),
  KEY `fk_certificate_skill` (`skillId`),
  CONSTRAINT `fk_certificate_skill` FOREIGN KEY (`skillId`) REFERENCES `skill` (`id`),
  CONSTRAINT `fk_certificate_user` FOREIGN KEY (`userId`) REFERENCES `user` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=617 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='证书管理表';
/*!40101 SET character_set_client = @saved_cs_client */;

