--
-- Table structure for table `equipmentoperationrecord`
--

DROP TABLE IF EXISTS `equipmentoperationrecord`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `equipmentoperationrecord` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '操作记录ID',
  `userId` bigint DEFAULT NULL COMMENT '操作人员ID，关联User表',
  `equipmentId` bigint DEFAULT NULL COMMENT '设备ID，关联Equipment表',
  `operateTime` datetime DEFAULT NULL COMMENT '操作时间',
  `operation` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '操作内容',
  `duration` int DEFAULT NULL COMMENT '操作时长(分钟)',
  `remarks` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '备注',
  `createTime` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updateTime` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `isDelete` tinyint NOT NULL DEFAULT '0' COMMENT '逻辑删除(0-正常,1-删除)',
  PRIMARY KEY (`id`),
  KEY `idx_user` (`userId`),
  KEY `idx_equipment` (`equipmentId`),
  KEY `idx_operateTime` (`operateTime`),
  CONSTRAINT `fk_oper_equipment` FOREIGN KEY (`equipmentId`) REFERENCES `equipment` (`id`),
  CONSTRAINT `fk_oper_user` FOREIGN KEY (`userId`) REFERENCES `user` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=801 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='设备操作记录表';
/*!40101 SET character_set_client = @saved_cs_client */;

