--
-- Table structure for table `equipmentskillrequirement`
--

DROP TABLE IF EXISTS `equipmentskillrequirement`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `equipmentskillrequirement` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT 'ID',
  `equipmentId` bigint DEFAULT NULL COMMENT '设备ID，关联Equipment表',
  `skillId` bigint DEFAULT NULL COMMENT '技能ID，关联Skill表',
  `requiredLevel` int DEFAULT NULL COMMENT '要求等级(数值)',
  `requiredCert` tinyint DEFAULT '0' COMMENT '是否需要认证(0-不需要,1-需要)',
  `description` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '备注',
  `createTime` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updateTime` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `isDelete` tinyint NOT NULL DEFAULT '0' COMMENT '逻辑删除(0-正常,1-删除)',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_equipment_skill` (`equipmentId`,`skillId`),
  KEY `fk_equip_req_skill` (`skillId`),
  CONSTRAINT `fk_equip_req_equip` FOREIGN KEY (`equipmentId`) REFERENCES `equipment` (`id`),
  CONSTRAINT `fk_equip_req_skill` FOREIGN KEY (`skillId`) REFERENCES `skill` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=461 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='设备技能要求表';
/*!40101 SET character_set_client = @saved_cs_client */;

