--
-- Table structure for table `skilllevelstandard`
--

DROP TABLE IF EXISTS `skilllevelstandard`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `skilllevelstandard` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '等级ID',
  `skillId` bigint DEFAULT NULL COMMENT '技能ID，关联Skill表',
  `level` int DEFAULT NULL COMMENT '等级数值(如1,2,3)',
  `levelName` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '等级名称(如初级、中级)',
  `description` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '等级描述',
  `minScore` int DEFAULT NULL COMMENT '最低分数(如用于评分范围)',
  `maxScore` int DEFAULT NULL COMMENT '最高分数',
  `createTime` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updateTime` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `isDelete` tinyint NOT NULL DEFAULT '0' COMMENT '逻辑删除(0-正常,1-删除)',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_skill_level` (`skillId`,`level`),
  CONSTRAINT `fk_skill_level_skill` FOREIGN KEY (`skillId`) REFERENCES `skill` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=301 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='技能等级标准表';
/*!40101 SET character_set_client = @saved_cs_client */;

