DROP TABLE IF EXISTS `trainingrecord`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `trainingrecord` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '培训记录ID',
  `userId` bigint DEFAULT NULL COMMENT '人员ID，关联User表',
  `skillId` bigint DEFAULT NULL COMMENT '培训技能ID，关联Skill表',
  `trainingName` varchar(200) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '培训名称',
  `startDate` date DEFAULT NULL COMMENT '培训开始日期',
  `endDate` date DEFAULT NULL COMMENT '培训结束日期',
  `hours` int DEFAULT NULL COMMENT '培训学时',
  `result` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '培训结果(如通过/未通过)',
  `certificateNo` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '获得证书编号',
  `createTime` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updateTime` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `isDelete` tinyint NOT NULL DEFAULT '0' COMMENT '逻辑删除(0-正常,1-删除)',
  PRIMARY KEY (`id`),
  KEY `idx_user` (`userId`),
  KEY `fk_training_skill` (`skillId`),
  CONSTRAINT `fk_training_skill` FOREIGN KEY (`skillId`) REFERENCES `skill` (`id`),
  CONSTRAINT `fk_training_user` FOREIGN KEY (`userId`) REFERENCES `user` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=301 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='培训记录表';
/*!40101 SET character_set_client = @saved_cs_client */;

