--
-- Table structure for table `userskill`
--

DROP TABLE IF EXISTS `userskill`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `userskill` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT 'ID',
  `userId` bigint DEFAULT NULL COMMENT '人员ID，关联User表',
  `skillId` bigint DEFAULT NULL COMMENT '技能ID，关联Skill表',
  `level` int DEFAULT NULL COMMENT '熟练程度等级',
  `levelId` bigint DEFAULT NULL COMMENT '关联等级标准ID(可选)',
  `certification` tinyint NOT NULL DEFAULT '0' COMMENT '是否获得认证(0-否,1-是)',
  `acquireDate` date DEFAULT NULL COMMENT '获取日期',
  `expireDate` date DEFAULT NULL COMMENT '有效期至',
  `createTime` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updateTime` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `isDelete` tinyint NOT NULL DEFAULT '0' COMMENT '逻辑删除(0-正常,1-删除)',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_user_skill` (`userId`,`skillId`),
  KEY `fk_user_skill_skill` (`skillId`),
  KEY `fk_user_skill_level` (`levelId`),
  CONSTRAINT `fk_user_skill_level` FOREIGN KEY (`levelId`) REFERENCES `skilllevelstandard` (`id`),
  CONSTRAINT `fk_user_skill_skill` FOREIGN KEY (`skillId`) REFERENCES `skill` (`id`),
  CONSTRAINT `fk_user_skill_user` FOREIGN KEY (`userId`) REFERENCES `user` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=1284 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='人员技能表';
/*!40101 SET character_set_client = @saved_cs_client */;

