INSERT INTO `emotion_report` VALUES (1912272022099165185,1899334965735927809,'daily','','[[1903511796248096769], [1903525469184208897], [1912097495566176258]]','根据分析，用户近期情绪以contempt为主（占比33.3%）。建议关注情绪变化规律，保持规律作息与适量运动。同时检测到happy情绪出现频率较高（33.3%），继续保持积极状态，可尝试记录快乐时刻增强正向循环（检测到该情绪表现强烈，请特别注意调节）','2025-04-16 06:29:13',0),(1912272203318263810,1899334965735927809,'daily','','[[1903511796248096769], [1903525469184208897], [1912097495566176258]]','根据分析，用户近期情绪以contempt为主（占比33.3%）。建议关注情绪变化规律，保持规律作息与适量运动。同时检测到happy情绪出现频率较高（33.3%），继续保持积极状态，可尝试记录快乐时刻增强正向循环（检测到该情绪表现强烈，请特别注意调节）','2025-04-16 06:29:56',0),(1912272203968380929,1899334965735927809,'daily','','[[1903511796248096769], [1903525469184208897], [1912097495566176258]]','根据分析，用户近期情绪以contempt为主（占比33.3%）。建议关注情绪变化规律，保持规律作息与适量运动。同时检测到happy情绪出现频率较高（33.3%），继续保持积极状态，可尝试记录快乐时刻增强正向循环（检测到该情绪表现强烈，请特别注意调节）','2025-04-16 06:29:56',0),(1912272272595582977,1899334965735927809,'daily','','[[1903511796248096769], [1903525469184208897], [1912097495566176258]]','根据分析，用户近期情绪以contempt为主（占比33.3%）。建议关注情绪变化规律，保持规律作息与适量运动。同时检测到happy情绪出现频率较高（33.3%），继续保持积极状态，可尝试记录快乐时刻增强正向循环（检测到该情绪表现强烈，请特别注意调节）','2025-04-16 06:30:12',0),(1912272302559690754,1899334965735927809,'daily','','[[1903511796248096769], [1903525469184208897], [1912097495566176258]]','根据分析，用户近期情绪以contempt为主（占比33.3%）。建议关注情绪变化规律，保持规律作息与适量运动。同时检测到happy情绪出现频率较高（33.3%），继续保持积极状态，可尝试记录快乐时刻增强正向循环（检测到该情绪表现强烈，请特别注意调节）','2025-04-16 06:30:19',0),(1912272828772876290,1899334965735927809,'daily','','[[1903511796248096769], [1903525469184208897], [1912097495566176258]]','根据分析，用户近期情绪以contempt为主（占比33.3%）。建议关注情绪变化规律，保持规律作息与适量运动。同时检测到happy情绪出现频率较高（33.3%），继续保持积极状态，可尝试记录快乐时刻增强正向循环（检测到该情绪表现强烈，请特别注意调节）','2025-04-16 06:32:25',0),(1912272901380472834,1899334965735927809,'daily','','[[1903511796248096769], [1903525469184208897], [1912097495566176258]]','根据分析，用户近期情绪以contempt为主（占比33.3%）。建议关注情绪变化规律，保持规律作息与适量运动。同时检测到happy情绪出现频率较高（33.3%），继续保持积极状态，可尝试记录快乐时刻增强正向循环（检测到该情绪表现强烈，请特别注意调节）','2025-04-16 06:32:42',0),(1912272948188905474,1899