  `alertTime` datetime DEFAULT NULL COMMENT '预警触发时间',
  `alertValue` varchar(1024) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '触发值（如实际能耗值、故障次数）',
  `alertLevel` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '预警等级（冗余）',
  `status` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT 'pending' COMMENT '处理状态：pending-待处理，resolved-已处理，ignored-已忽略',
  `handledBy` bigint DEFAULT NULL COMMENT '处理人ID（关联user表）',
  `handleRemark` varchar(1024) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '处理备注',
  `handleTime` datetime DEFAULT NULL COMMENT '处理时间',
  `editTime` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '编辑时间',
  `createTime` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updateTime` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `isDelete` tinyint DEFAULT '0' COMMENT '是否删除',
  PRIMARY KEY (`id`),
  KEY `idx_ruleId` (`ruleId`),
  KEY `idx_target` (`targetType`,`targetId`),
  KEY `idx_status` (`status`),
  KEY `idx_alertTime` (`alertTime`)
) ENGINE=InnoDB AUTO_INCREMENT=301 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='预警记录表';
