--
-- Table structure for table `alertrule`
--

DROP TABLE IF EXISTS `alertrule`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `alertrule` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `ruleName` varchar(256) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '规则名称',
  `ruleType` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '规则类型：fault-故障预警，energy-能耗预警',
  `targetType` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '目标类型：global-全局，room-机房，device-设备',
  `targetId` bigint DEFAULT NULL COMMENT '目标ID（当targetType为room或device时有效）',
  `thresholdConfig` json DEFAULT NULL COMMENT '阈值配置（JSON格式，如{"maxFaultCount":5,"maxDuration":3600}）',
  `alertLevel` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '预警等级：warning-警告，critical-严重',
  `notifyMethods` varchar(256) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '通知方式：大屏(display)/系统消息(message)，可多选，逗号分隔',
  `enabled` tinyint DEFAULT '1' COMMENT '是否启用：0-禁用，1-启用',
  `description` varchar(1024) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '规则描述',
  `editTime` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '编辑时间',
  `createTime` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updateTime` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `isDelete` tinyint DEFAULT '0' COMMENT '是否删除',
  PRIMARY KEY (`id`),
  KEY `idx_ruleType` (`ruleType`),
  KEY `idx_target` (`targetType`,`targetId`),
  KEY `idx_enabled` (`enabled`)
) ENGINE=InnoDB AUTO_INCREMENT=151 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='预警规则表';
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `alertrule`
--

LOCK TABLES `alertrule` WRITE;
/*!40000 ALTER TABLE `alertrule` DISABLE KEYS */;
