--
-- Table structure for table `consumable`
--

DROP TABLE IF EXISTS `consumable`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `consumable` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `consumableName` varchar(256) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '耗材名称',
  `consumableType` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '耗材类型：printer-打印耗材，computer-电脑耗材，network-网络耗材，other-其他',
  `specification` varchar(256) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '规格型号',
  `unit` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '单位',
  `stock` int DEFAULT NULL COMMENT '当前库存',
  `minStock` int DEFAULT NULL COMMENT '最低库存阈值',
  `price` decimal(10,2) DEFAULT NULL COMMENT '单价（元）',
  `supplier` varchar(256) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '供应商',
  `responsibleId` bigint DEFAULT NULL COMMENT '负责人ID',
  `responsibleName` varchar(256) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '负责人姓名',
  `description` varchar(1024) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '描述',
  `editTime` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '编辑时间',
  `createTime` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updateTime` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `isDelete` tinyint DEFAULT '0' COMMENT '是否删除',
  PRIMARY KEY (`id`),
  KEY `idx_consumableName` (`consumableName`),
  KEY `idx_consumableType` (`consumableType`)
) ENGINE=InnoDB AUTO_INCREMENT=151 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='耗材表';
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `consumable`
--

LOCK TABLES `consumable` WRITE;
/*!40000 ALTER TABLE `consumable` DISABLE KEYS */;
