--
-- Table structure for table `dataanomaly`
--

DROP TABLE IF EXISTS `dataanomaly`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `dataanomaly` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `dataSourceId` bigint DEFAULT NULL COMMENT '数据源ID（关联data_source表）',
  `sourceTable` varchar(256) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '源表名',
  `recordId` varchar(256) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '源记录主键值（转为字符串）',
  `fieldName` varchar(256) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '异常字段名',
  `fieldValue` text COLLATE utf8mb4_unicode_ci COMMENT '异常字段值',
  `anomalyRule` varchar(1024) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '触发的异常规则描述',
  `status` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT 'pending' COMMENT '处理状态：pending-待复核，resolved-已处理，ignored-已忽略',
  `remark` varchar(1024) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '复核备注',
  `handledBy` bigint DEFAULT NULL COMMENT '处理人ID（关联user表）',
  `handleTime` datetime DEFAULT NULL COMMENT '处理时间',
  `editTime` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '编辑时间',
  `createTime` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updateTime` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `isDelete` tinyint DEFAULT '0' COMMENT '是否删除',
  PRIMARY KEY (`id`),
  KEY `idx_dataSourceId` (`dataSourceId`),
  KEY `idx_status` (`status`),
  KEY `idx_sourceTable` (`sourceTable`)
) ENGINE=InnoDB AUTO_INCREMENT=201 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='异常数据表';
/*!40101 SET character_set_client = @saved_cs_client */;

