--
-- Table structure for table `datasource`
--

DROP TABLE IF EXISTS `datasource`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `datasource` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `sourceName` varchar(256) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '数据源名称',
  `dbType` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '数据库类型：mysql, oracle, sqlserver等',
  `host` varchar(256) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '主机地址',
  `port` int DEFAULT NULL COMMENT '端口',
  `databaseName` varchar(256) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '数据库名',
  `username` varchar(256) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '用户名',
  `password` varchar(1024) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '密码（加密存储）',
  `description` varchar(1024) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '描述',
  `editTime` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '编辑时间',
  `createTime` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updateTime` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `isDelete` tinyint DEFAULT '0' COMMENT '是否删除',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_sourceName` (`sourceName`),
  KEY `idx_dbType` (`dbType`)
) ENGINE=InnoDB AUTO_INCREMENT=51 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='数据源配置表';
/*!40101 SET character_set_client = @saved_cs_client */;

