--
-- Table structure for table `device`
--

DROP TABLE IF EXISTS `device`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `device` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `deviceName` varchar(256) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '设备名称',
  `deviceModel` varchar(256) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '设备型号',
  `roomId` bigint DEFAULT NULL COMMENT '所属机房ID（关联room表）',
  `position` varchar(128) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '位置编号（如A01）',
  `status` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT 'idle' COMMENT '状态：idle-空闲，in_use-使用中，fault-故障，maintain-维护',
  `purchaseDate` date DEFAULT NULL COMMENT '购买日期',
  `serviceLife` int DEFAULT NULL COMMENT '服役年限（年）',
  `energyRating` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '能耗等级',
  `deviceType` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '设备类型：office-办公，teaching-教学，server-服务器，network-网络设备，other-其他',
  `responsibleId` bigint DEFAULT NULL COMMENT '负责人ID',
  `responsibleName` varchar(256) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '负责人姓名',
  `currentUserId` bigint DEFAULT NULL COMMENT '当前使用人ID',
  `currentUserName` varchar(256) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '当前使用人姓名',
  `power` int DEFAULT NULL COMMENT '设备功率（W）',
  `description` varchar(1024) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '描述',
  `editTime` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '编辑时间',
  `createTime` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updateTime` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `isDelete` tinyint DEFAULT '0' COMMENT '是否删除',
  PRIMARY KEY (`id`),
  KEY `idx_roomId` (`roomId`),
  KEY `idx_status` (`status`),
  KEY `idx_purchaseDate` (`purchaseDate`)
) ENGINE=InnoDB AUTO_INCREMENT=201 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='设备表';
/*!40101 SET character_set_client = @saved_cs_client */;

