--
-- Table structure for table `energyconsumption`
--

DROP TABLE IF EXISTS `energyconsumption`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `energyconsumption` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `deviceId` bigint DEFAULT NULL COMMENT '设备ID（如果按设备采集，关联device表）',
  `roomId` bigint DEFAULT NULL COMMENT '机房ID（如果按机房采集，关联room表）',
  `recordTime` datetime DEFAULT NULL COMMENT '记录时间',
  `consumption` float DEFAULT NULL COMMENT '能耗值',
  `unit` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT 'kWh' COMMENT '单位',
  `editTime` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '编辑时间',
  `createTime` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updateTime` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `isDelete` tinyint DEFAULT '0' COMMENT '是否删除',
  PRIMARY KEY (`id`),
  KEY `idx_deviceId` (`deviceId`),
  KEY `idx_roomId` (`roomId`),
  KEY `idx_recordTime` (`recordTime`),
  CONSTRAINT `energyconsumption_chk_1` CHECK (((`deviceId` is null) or (`roomId` is not null)))
) ENGINE=InnoDB AUTO_INCREMENT=301 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='能耗记录表';
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `energyconsumption`
--

LOCK TABLES `energyconsumption` WRITE;
/*!40000 ALTER TABLE `energyconsumption` DISABLE KEYS */;
