--
-- Table structure for table `fault`
--

DROP TABLE IF EXISTS `fault`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `fault` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `deviceId` bigint DEFAULT NULL COMMENT '故障设备ID（关联device表）',
  `reportedBy` bigint DEFAULT NULL COMMENT '报告人ID（关联user表）',
  `faultTime` datetime DEFAULT NULL COMMENT '故障发生时间',
  `faultType` varchar(256) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '故障类型',
  `description` varchar(1024) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '故障描述',
  `status` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT 'pending' COMMENT '处理状态：pending-待处理，processing-处理中，resolved-已修复',
  `repairTime` datetime DEFAULT NULL COMMENT '修复时间',
  `remark` varchar(1024) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '处理备注',
  `editTime` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '编辑时间',
  `createTime` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updateTime` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `isDelete` tinyint DEFAULT '0' COMMENT '是否删除',
  PRIMARY KEY (`id`),
  KEY `idx_deviceId` (`deviceId`),
  KEY `idx_reportedBy` (`reportedBy`),
  KEY `idx_status` (`status`),
  KEY `idx_faultTime` (`faultTime`)
) ENGINE=InnoDB AUTO_INCREMENT=251 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='故障记录表';
/*!40101 SET character_set_client = @saved_cs_client */;

