--
-- Table structure for table `fieldmapping`
--

DROP TABLE IF EXISTS `fieldmapping`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `fieldmapping` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `dataSourceId` bigint DEFAULT NULL COMMENT '关联数据源ID（data_source表）',
  `sourceTable` varchar(256) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '源表名',
  `targetTable` varchar(256) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '目标表名（如device, reservation等）',
  `fieldMappings` json DEFAULT NULL COMMENT '字段映射关系（JSON格式，如{"source_field":"target_field"}）',
  `cleaningRules` json DEFAULT NULL COMMENT '清洗规则（JSON格式，如{"deduplication":true,"fill_na":{"status":"idle"}}）',
  `enabled` tinyint DEFAULT '1' COMMENT '是否启用',
  `editTime` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '编辑时间',
  `createTime` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updateTime` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `isDelete` tinyint DEFAULT '0' COMMENT '是否删除',
  PRIMARY KEY (`id`),
  KEY `idx_dataSourceId` (`dataSourceId`),
  KEY `idx_targetTable` (`targetTable`)
) ENGINE=InnoDB AUTO_INCREMENT=101 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='字段映射表';
/*!40101 SET character_set_client = @saved_cs_client */;

