--
-- Table structure for table `reservation`
--

DROP TABLE IF EXISTS `reservation`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `reservation` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `userId` bigint DEFAULT NULL COMMENT '预约用户ID（关联user表）',
  `deviceId` bigint DEFAULT NULL COMMENT '预约设备ID（关联device表）',
  `startTime` datetime DEFAULT NULL COMMENT '预约开始时间',
  `endTime` datetime DEFAULT NULL COMMENT '预约结束时间',
  `status` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT 'scheduled' COMMENT '状态：scheduled-待使用，completed-已使用，cancelled-已取消，expired-过期',
  `remark` varchar(1024) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '备注',
  `editTime` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '编辑时间',
  `createTime` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updateTime` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `isDelete` tinyint DEFAULT '0' COMMENT '是否删除',
  PRIMARY KEY (`id`),
  KEY `idx_userId` (`userId`),
  KEY `idx_deviceId` (`deviceId`),
  KEY `idx_startTime` (`startTime`),
  KEY `idx_endTime` (`endTime`),
  KEY `idx_status` (`status`)
) ENGINE=InnoDB AUTO_INCREMENT=301 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='预约记录表';
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `reservation`
--

LOCK TABLES `reservation` WRITE;
