--
-- Table structure for table `room`
--

DROP TABLE IF EXISTS `room`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `room` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `roomName` varchar(256) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '机房名称',
  `location` varchar(512) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '位置（如：实验楼A座301）',
  `capacity` int DEFAULT NULL COMMENT '容纳人数/设备数',
  `layoutConfig` text COLLATE utf8mb4_unicode_ci COMMENT '拓扑布局配置（JSON格式，存储座位坐标等信息）',
  `purpose` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '用途：teaching-教学，research-科研，office-办公，server-服务器机房，other-其他',
  `roomType` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '机房类型：computer-计算机机房，server-服务器机房，network-网络机房，other-其他',
  `responsibleId` bigint DEFAULT NULL COMMENT '负责人ID',
  `responsibleName` varchar(256) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '负责人姓名',
