--
-- Table structure for table `usagelog`
--

DROP TABLE IF EXISTS `usagelog`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `usagelog` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `userId` bigint DEFAULT NULL COMMENT '使用用户ID（关联user表）',
  `deviceId` bigint DEFAULT NULL COMMENT '使用设备ID（关联device表）',
  `reservationId` bigint DEFAULT NULL COMMENT '关联预约记录ID（可为空）',
  `startTime` datetime DEFAULT NULL COMMENT '开始使用时间',
  `endTime` datetime DEFAULT NULL COMMENT '结束使用时间',
  `duration` int DEFAULT NULL COMMENT '使用时长（秒）',
  `editTime` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '编辑时间',
  `createTime` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updateTime` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `isDelete` tinyint DEFAULT '0' COMMENT '是否删除',
  PRIMARY KEY (`id`),
  KEY `idx_userId` (`userId`),
  KEY `idx_deviceId` (`deviceId`),
  KEY `idx_reservationId` (`reservationId`),
  KEY `idx_startTime` (`startTime`)
) ENGINE=InnoDB AUTO_INCREMENT=401 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='使用记录表';
/*!40101 SET character_set_client = @saved_cs_client */;

